	if (l <= st && en <= r) {

		add(u, st, en, c);

		return;

	}

	down(u, st, en);

	int md = st + en >> 1;

	if (l <= md) add(u * 2, st, md, l, r, c);

	if (r > md) add(u * 2 + 1, md + 1, en, l, r, c);

	update(u);

