    long dist;

    int v;

} rte;



bool operator< (const rte a, const rte b){

    return a.dist > b.dist;  // ascend

}



vector<edge> G[MAX_V];



long d[MAX_V];



void dijkstra(int s, int t);



int main(){



    ios::sync_with_stdio(false);

    cin.tie(nullptr);



