    cin >> N >> M;



    int L[M], R[M], C[M];

    for(int i = 0; i < M; i++){

        cin >> L[i] >> R[i] >> C[i] ;

        L[i]--; R[i]--; 

    }



    int cnt = 0;



    bool bonded[N]; fill(bonded, bonded + N, false);

    for(int i = 0; i<M; i++){

        G[L[i]].emplace_back(edge{R[i], C[i]});

    }



    for(int i = 0; i<N-1; i++){

        G[i+1].emplace_back(edge{i, 0});

    }



    dijkstra(0, N);



