    else cout << d[N-1] << endl;



    return 0;



}



void dijkstra(int s, int V){



    fill(d, d + V, INF);



    priority_queue< rte > que;

    d[s] = 0;

    que.push(rte{d[s], s});



    while(!que.empty()){

        rte now = que.top(); que.pop();

        if(now.dist > d[now.v]) continue;

        for(edge e : G[now.v]){

            if(d[e.to] > d[now.v] + e.cost){

                d[e.to] = d[now.v] + e.cost;

                que.push(rte{d[e.to], e.to});

            }



        }

    }

}

